#include <stdio.h>
#include <openssl/bn.h>

int main() {
    BN_CTX *ctx = BN_CTX_new();
    BIGNUM *n = BN_new();
    BIGNUM *e = BN_new();
    BIGNUM *s = BN_new();
    BIGNUM *m = BN_new();

    // Dán các giá trị bạn vừa tìm được vào đây
    BN_hex2bn(&n, "");
    BN_hex2bn(&e, "10001"); 
    BN_hex2bn(&s, "");

    // Tính M = S^e mod n
    BN_mod_exp(m, s, e, n, ctx);

    char *result = BN_bn2hex(m);
    printf("Kết quả giải mã chữ ký (M):\n%s\n", result);

    OPENSSL_free(result);
    return 0;
}
